// 다운로드 : 
// 호출     :
//==================================================================================================================
scwin.selfTransClntNo;
scwin.onReqNo;
scwin.selfTransClntNm;
scwin.lineCd;
scwin.mrn;
scwin.msn;
scwin.hsn;
scwin.blNo;
scwin.nowDt;
scwin.nextDt;
scwin.systemPathKey;
scwin.systemPathVal;
scwin.obj;
// scwin.MSG_OP_ERR_001;
// scwin.MSG_OP_ERR_002;
// scwin.MSG_OP_ERR_003;
// scwin.MSG_OP_ERR_004;
// scwin.MSG_OP_ERR_005;
// scwin.MSG_OP_ERR_006;
