// scwin.MSG_OP_CFM_001;
// scwin.MSG_OP_CFM_002;
scwin.bf_admitClsCd;

scwin.onpageload = async function() {
    const codeOptions = [
          { grpCd : "OP292", compID : "acb_jeRmk" }
        , { grpCd : "OP224", compID : "gr_ImportOnRequest:selfPrgsStsClsCd" }
        , { grpCd : "SD133", compID : "gr_ImportOnRequest:offRtrnClsCd" }
    ];
    $c.data.setCommonCode(codeOptions, scwin.commonCodeCallBack);

    scwin.selfTransClntNo = $c.data.getParameter("selfTransClntNo") == null ? ""
                          : $c.data.getParameter("selfTransClntNo"); // 자가운송사

    scwin.onReqNo         = $c.data.getParameter("onReqNo") == null ? ""
                          : $c.data.getParameter("onReqNo"); // 상차요청번호

    scwin.selfTransClntNm = $c.data.getParameter("selfTransClntNm") == null ? ""
                          : $c.data.getParameter("selfTransClntNm"); // 자가운송사명

    scwin.lineCd          = $c.data.getParameter("lineCd") == null ? ""
                          : $c.data.getParameter("lineCd"); // 자가운송사명

    scwin.mrn             = $c.data.getParameter("mrn") == null ? ""
                          : $c.data.getParameter("mrn"); // mrn

    scwin.msn             = $c.data.getParameter("msn") == null ? ""
                          : $c.data.getParameter("msn"); // msn

    scwin.hsn             = $c.data.getParameter("hsn") == null ? ""
                          : $c.data.getParameter("hsn"); // hsn

    scwin.blNo            = $c.data.getParameter("blNo") == null ? ""
                          : $c.data.getParameter("blNo"); // hsn

    scwin.nowDt   = $c.date.getServerDateTime("yyyyMMdd");
    // DDate.getNextDate(scwin.nowDt , 1)
    scwin.nextDt  = $c.date.addDate(scwin.nowDt, 1);

    scwin.systemPathKey =  DFWConstants.FILE_UPLOAD_SYSTEM_PATH ;
	scwin.systemPathVal =  "/cm/bc/cstmrcardmgnt/cstmrcardmgnt";

    scwin.obj = null;
    scwin.MSG_OP_ERR_001 = "오더번호는 이미 생성되어 있습니다";
    scwin.MSG_OP_ERR_002 = "수입상차 요청 승인 내역이 없어, 오더를 생성할 수 없습니다";
    scwin.MSG_OP_ERR_003 = "승인 구분이 승인 또는 접수인 경우만 가능합니다.";
    scwin.MSG_OP_ERR_004 = "오더 번호가 존재하지 않습니다. 오더 번호를 확인 하세요.";
    // scwin.MSG_OP_ERR_005 = "@은(는) @보다 커야합니다.";
    scwin.MSG_OP_ERR_005 = "%1은(는) %2보다 커야합니다.";
    scwin.MSG_OP_ERR_006 = "오류 기타 사유 및 참고사항이 100Byte 를 초과했습니다.";
    scwin.MSG_OP_ERR_007 = "이미 오더가 발생되어 삭제 할수 없습니다";
    scwin.MSG_OP_ERR_008 = "삭제할 자료를 먼저 체크하십시오";
    scwin.MSG_OP_ERR_009 = "수입상차목록 중 오더를 생성할 데이타를 입력하십시오.";
    scwin.MSG_OP_ERR_010 = "요청한 컨테이너보다 많은 수를 승인하고자 합니다. 요청데이타를 확인바랍니다.";
    scwin.MSG_OP_ERR_011 = "해당 요청건은 접수 또는 오류처리만 가능한 요청입니다.";
    scwin.MSG_OP_ERR_012 = "체선일자가 현재일자보다 경과하여 저장할 수 없습니다."
    scwin.MSG_OP_ERR_013 = "면허되지 않은 건입니다. 반출할 수 없습니다.";
    scwin.MSG_OP_INF_001 = "승인구분이 오류일 경우에만 조회가능합나다.";
    scwin.MSG_OP_INF_002 = "승인취소 후, 오류 처리 하세요. ";
    scwin.MSG_OP_CFM_001 = "승인을 취소하시겠습니까?";
    scwin.MSG_OP_CFM_002 = "마스터 BL 면허가 완료되지 않았습니다. 그래도 처리하시겠습니까?";
    scwin.bf_admitClsCd = "";

    ds_searchLineCd.set("sysCd", "CommonEBC");
    ds_searchLineCd.set("queryId", "retrieveCommCdInfo");
    ds_searchLineCd.set("param3", "SD225");
    ds_searchLineCd.set("param2", "");
    ds_searchLineCd.set("param1", "");
    $c.sbm.execute(sbm_retrieveCommonPopupCMD);

};

scwin.commonCodeCallBack = async function(){
    // 접수구분
    ds_searchRecptClsCd.set("grpCd", "OP179");
    var rs = await $c.sbm.execute(sbm_recptClsCd);
    if (rs.responseJSON.resultDataSet[0].Msg == "SUCC"){
        ds_recptClsCd.setJSON(rs.responseJSON.GAUCE);
    };
    acb_jeRmk.setValue("");
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = async function() {
    $p.setTimeout(function() {

        // $p.setTimeout(function() {
        //     // 수입상차 요청 승인 관련

        //     // ed_srchSelfTransCoCd.setValue("100477");
        //     // ed_srchOnReqNo.setValue("200708210378");
        //     // ed_srchOnReqNo.setValue("201606211161");
        //     // ed_srchOnReqNo.setValue("201410061604");
        //     // ed_srchOnReqNo.setValue("201408050817");
        //     // ed_srchOnReqNo.setValue("201208080016");
        //     // ed_srchOnReqNo.setValue("201302180451");
        //     // ed_srchOnReqNo.setValue("200810230246");
        //     // ed_srchOnReqNo.setValue("200809290449");

        //     // 첨부관련
        //     // ed_srchSelfTransCoCd.setValue("102823");
        //     // ed_srchOnReqNo.setValue("201302270278");

        //     // ed_srchSelfTransCoCd.setValue("228178");
        //     // ed_srchOnReqNo.setValue("202507250455");

        //     ed_srchSelfTransCoCd.setValue("228857");
        //     ed_srchOnReqNo.setValue("201201020298");

        //     ed_srchSelfTransCoCd.focus();
        //     ed_srchSelfTransCoCd.blur();

        // }, {"delay":150});

        ds_srchCond.set("selfTransClntNo", scwin.selfTransClntNo);
        ds_srchCond.set("onReqNo", scwin.onReqNo);
        ds_srchCond.set("lineCd", scwin.lineCd);

        ed_srchSelfTransCoCd.setValue(scwin.selfTransClntNo);
        ed_srchSelfTransCoCd.focus();
        ed_srchSelfTransCoCd.blur();
        ed_srchOnReqNo.setValue(scwin.onReqNo);

        ed_srchSelfTransCoNm.setValue(scwin.selfTransClntNm);

        if (scwin.lineCd == "TSL"){
            ds_srchCond.set("mrn", scwin.mrn);
            ds_srchCond.set("msn", scwin.msn);
            ds_srchCond.set("hsn", scwin.hsn);
            ds_srchCond.set("blNo", scwin.blNo);
        }
        if (!$c.gus.cfIsNull(scwin.mrn)){
            ds_srchCond.set("mrn", scwin.mrn);
            ds_srchCond.set("msn", scwin.msn);
            ds_srchCond.set("hsn", scwin.hsn);
            ds_srchCond.set("blNo", scwin.blNo);
        }

        $p.setTimeout(function() {

            $c.gus.cfDisableObjects([rd_dpctYn]);

            if (ds_srchCond.get('onReqNo') == "" && ds_srchCond.get('selfTransClntNo') == ""){
                txt_admitClsCd.setValue("승인구분");
                return;
            }

            //await $c.win.alert("kkk::"+ds_srchCond.ExportData(1,ds_srchCond.getRowCount(),true));
            scwin.f_Retrieve();

            // 증빙서류 유무 조회
            scwin.f_getUploadFileList();

            if (ds_attach.getRowCount() > 0){
                grp_fileSection.show("");
            }

            if (ds_OnRequest.getCellData(0, "lineCd") == "TSL" || ds_OnRequest.getCellData(0, "lineCd") == "SKR") {
                txt_admitClsCd.setValue("승인구분/선수납");
                acb_admitClsCd2.show("");

            }else{
                txt_admitClsCd.setValue("승인구분");
                acb_admitClsCd2.hide("");
            }
            if ($c.gus.cfIsNull(ds_OnRequest.getCellData(0, "lineCd"))){
                txt_admitClsCd.setValue("승인구분");
            }

        }, {"delay":200});
    }, {"delay":150});
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function (){
    if (!await $c.gus.cfValidate([tb_srchCond]) ) return;

    ds_srchCond.set('selfTransClntNo', ed_srchSelfTransCoCd.getValue());
    ds_srchCond.set('impExpClsCd', 'I');//ed_srchOnReqNo.getValue();
    //ds_srchCond.get('stDt', '00010101';
    //ds_srchCond.get('endDt', '99991231';
    $c.sbm.execute(sbm_retrieveImportOnRequest);

    scwin.f_getUploadFileList();

    /*
    if (await $c.gus.cfIsNull((ds_OnRequest.getCellData(0, "prebilgYn"))) ||  (ds_OnRequest.getCellData(0, "prebilgYn") == 1 )){
        acb_admitClsCd2.setValue("Y";
    }else{
        acb_admitClsCd2.setValue("N";
    }
    */
    //await $c.win.alert("cc::"+ds_OnRequest.getCellData(0, "prebilgYn"));
};

//-------------------------------------------------------------------------
// 조회 조건 초기화
//-------------------------------------------------------------------------
scwin.f_FieldClear = function (){
    $c.gus.cfInitObjects([ed_srchSelfTransCoCd,ed_srchSelfTransCoNm,ed_srchOnReqNo]);
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function (){
    var cntr20Cnt = 0;
    var cntr40Cnt = 0;

    if (ds_OnRequest.getRowCount() == 0) return;
    if (ds_OnRequest.getCellData(0, 'admitClsCd') != 'P' ) {
        if (!await $c.gus.cfValidate([tb_data3]) ) return;
    }

    /* if (ds_ImportOnRequest.isUpdated==false){
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001,["수입 상차 요청 승인"]); //변경된 정보가 없습니다.
        return;
    } */

    if ((ds_OnRequest.getCellData(0, "lineCd") == "WHL" || ds_OnRequest.getCellData(0, "lineCd") == "IAL") 
     && ds_OnRequest.getCellData(0, "lane") != "KSI" 
     && (ds_OnRequest.getCellData(0, 'admitClsCd') != 'R' && ds_OnRequest.getCellData(0, 'admitClsCd') != 'E' )){
        await $c.gus.cfAlertMsg(scwin.MSG_OP_ERR_011);
    }
    if (ds_OnRequest.getCellData(0, 'admitClsCd') == 'O') {
        if (ds_OnRequest.getCellData(0, "odrNo") == "") {
            await $c.gus.cfAlertMsg(scwin.MSG_OP_ERR_004);
            return;
        }
    }
    //라인코드가 SITC이고, ODR_CTRL_CLS_CD = 3 인경우에 체선일자 체크
    if (ds_OnRequest.getCellData(0, "lineCd") == "SITC" && ds_OnRequest.getCellData(0, "odrCtrlClsCd") == "3") {
        var sysDate = $c.date.getServerDateTime("yyyyMMdd");
        var demDate = ica_demDt.getValue();
        //시스템 날짜와 체선일자를 비교하여 작거나 같을경우에만 저장가능
        if (parseInt(demDate) < parseInt(sysDate)) {
            await $c.gus.cfAlertMsg(scwin.MSG_OP_ERR_012);
            ica_demDt.focus();
            return;
        }
    }

    //라인코드가 TSL이면 상차예정일, 반납지, 반납예정기한일에 빈값이 없는지 체크한다.
    //if (ds_OnRequest.getCellData(0, "lineCd") == "TSL" || ds_OnRequest.getCellData(0, "lineCd") == "EAS") { // 김아름 2011.11.23
    for(var i = 0 ; i < ds_ImportOnRequest.getRowCount(); i++) {
        //취소한건은 검사되지 않도록함
        // if (ds_ImportOnRequest.RowStatus(i) > 0) {
        if (ds_ImportOnRequest.getRowStatus(i) != "R") {
            if (ds_ImportOnRequest.getCellData(i, "onIntendDt") == "" || await $c.gus.cfIsNull(ds_ImportOnRequest.getCellData(i, "onIntendDt"))){
                await $c.gus.cfAlertMsg(MSG_CM_ERR_018, ["상차예정일"]);
                return false;
            }
            if (ds_ImportOnRequest.getCellData(i, "rtrnWrkPlNm") == "" || await $c.gus.cfIsNull(ds_ImportOnRequest.getCellData(i, "rtrnWrkPlNm"))){
                await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["반납지"]);
                return false;
            }
            if (ds_ImportOnRequest.getCellData(i, "rtrnIntendPrdDt") == "" || await $c.gus.cfIsNull(ds_ImportOnRequest.getCellData(i, "rtrnIntendPrdDt"))){
                await $c.gus.cfAlertMsg(MSG_CM_ERR_018, ["반납예정기한일"]);
                return false;
            }
        }

        //요청수량 체크(이미 승인한 데이타)
        if (ds_ImportOnRequest.getCellData(i, "selfPrgsStsClsCd") == "W"){
            if (ds_ImportOnRequest.getCellData(i, "nrm").substring(0,2) == "20" ){
                cntr20Cnt++;
            }
            if (ds_ImportOnRequest.getCellData(i, "nrm").substring(0,2) == "40" 
             || ds_ImportOnRequest.getCellData(i, "nrm").substring(0,2) == "45"){
                cntr40Cnt++;
            }
        }
        // if (ds_ImportOnRequest.getRowStatus(i) ==3){
        if (ds_ImportOnRequest.getRowStatus(i) == "U"){
            ds_ImportOnRequest.setCellData(i, 'admitClsCd', ds_OnRequest.getCellData(0, 'admitClsCd'));
            if (ds_ImportOnRequest.getCellData(i, 'onIntendDt')      != '' 
             || ds_ImportOnRequest.getCellData(i, 'rtrnWrkPlNm')     != '' 
             || ds_ImportOnRequest.getCellData(i, 'rtrnIntendPrdDt') != ''
            ){
                if (ds_ImportOnRequest.getCellData(i, 'onIntendDt') == '') {
                    await $c.win.alert('상차예정일을 입력하세요.'); 
                    return;
                }
                if (ds_ImportOnRequest.getCellData(i, 'rtrnWrkPlNm') == '') {
                    await $c.win.alert('반납지를 입력하세요.'); 
                    return;
                }
                if (ds_ImportOnRequest.getCellData(i, 'rtrnIntendPrdDt') == '') {
                    await $c.win.alert('반납예정 기한일을 입력하세요.'); 
                    return;
                }
            }
            if (ica_demDt.getValue().length > 0) {  //체선일(ica_demDt.getValue())이 null 아닌 경우만 Check
                if (ds_ImportOnRequest.getCellData(i, 'onIntendDt') > ica_demDt.getValue()){
                    ds_ImportOnRequest.setRowPosition(i);
                    await $c.gus.cfAlertMsg(scwin.MSG_OP_ERR_005,["체선일자","상차예정일"]);
                    return;
                }
                if (ds_ImportOnRequest.getCellData(i, 'onIntendDt') > ds_ImportOnRequest.getCellData(i, 'rtrnIntendPrdDt')){
                    ds_ImportOnRequest.setRowPosition(i);
                    await $c.gus.cfAlertMsg(scwin.MSG_OP_ERR_005,["반납예정 기한일","상차예정일"]);
                    return;
                }
            } else {
                if (ds_ImportOnRequest.getCellData(i, 'onIntendDt') > ds_ImportOnRequest.getCellData(i, 'rtrnIntendPrdDt')){
                    ds_ImportOnRequest.setRowPosition(i);
                    await $c.gus.cfAlertMsg(scwin.MSG_OP_ERR_005,["반납예정 기한일","상차예정일"]);
                    return;
                }
            }
            if (acb_admitClsCd.getValue() == 'C' || acb_admitClsCd.getValue() == 'O') {
                if (ds_ImportOnRequest.getCellData(i, "selfPrgsStsClsCd") == 'W'){
                    ds_ImportOnRequest.setCellData(i, "gubun", '2');
                }
            }
            //요청수량 체크(승인할 데이타)
            if (ds_ImportOnRequest.getCellData(i, "nrm").substring(0,2) == "20"
             && ds_ImportOnRequest.getCellData(i, "selfPrgsStsClsCd") != "W"){
                cntr20Cnt++;
            }
            if ((ds_ImportOnRequest.getCellData(i, "nrm").substring(0,2) == "40" || ds_ImportOnRequest.getCellData(i, "nrm").substring(0,2) == "45") 
             && ds_ImportOnRequest.getCellData(i, "selfPrgsStsClsCd") != "W" ){
                cntr40Cnt++;
            }
        }
        // if (ds_ImportOnRequest.getRowStatus(i) ==3 || ds_ImportOnRequest.getRowStatus(i) ==1){
        if (ds_ImportOnRequest.getRowStatus(i) == "U" || ds_ImportOnRequest.getRowStatus(i) == "C"){
            if (ds_OnRequest.getCellData(0, "demDt") != "") {
                if (ds_OnRequest.getCellData(0, "demDt") < ds_ImportOnRequest.getCellData(i, "onIntendDt")) {
                    ds_ImportOnRequest.setRowPosition(i);
                    await $c.gus.cfAlertMsg(scwin.MSG_OP_ERR_005,["체선일자","상차예정일"]);
                    return;
                }
            }
        }
    }
    //}

    //승인구분이 오류(E)이면  넘어감. 2009.01.21
    //pcy
    if (acb_admitClsCd.getValue() != 'E'
        && ds_OnRequest.getCellData(0, "lineCd") != "TSL"
        && ds_OnRequest.getCellData(0, "lineCd") != "EAS"
        && ds_OnRequest.getCellData(0, "lineCd") != "SKR"
        && ds_OnRequest.getCellData(0, "lineCd") != "NOLS"
        && ds_OnRequest.getCellData(0, "lineCd") != "TCLC"
        && ds_OnRequest.getCellData(0, "lineCd") != "SOFC"
        && ds_OnRequest.getCellData(0, "lineCd") != "TMSC"	//2014.09.22 TMSC라인 추가
        && ds_OnRequest.getCellData(0, "lineCd") != "SITC"
        && ds_OnRequest.getCellData(0, "lineCd") != "COH"	//2014.11.20 COH 라인추가
        && ds_OnRequest.getCellData(0, "lineCd") != "YNK"	//2015.05.15 YNK 라인추가
        && ds_OnRequest.getCellData(0, "lineCd") != "TJM"	//2015.05.20 TJM 라인추가
        && ds_OnRequest.getCellData(0, "lineCd") != "MAS"	//2016.02.04 MAS 라인추가
        && ds_OnRequest.getCellData(0, "lineCd") != "JJS"	//2016.04.11 JJS 라인추가
        && ds_OnRequest.getCellData(0, "lineCd") != "APL"	//2016.05.30 APL 라인추가
        && ds_OnRequest.getCellData(0, "lineCd") != "DWH"	//2016.08.17 DWH 라인추가
        && ds_OnRequest.getCellData(0, "lineCd") != "COS"	//2017.02.01 COS 라인추가
        && ds_OnRequest.getCellData(0, "lineCd") != "MOL"	//2017.03.23 MOL 라인추가
        && ds_OnRequest.getCellData(0, "lineCd") != "RHT"	//2017.04.05 RHT 라인추가
        && ds_OnRequest.getCellData(0, "lineCd") != "ONE"	//2018.03.07 ONE 라인추가
        && ds_OnRequest.getCellData(0, "lineCd") != "SWIL"
    ){
        if (cntr20Cnt > ds_OnRequest.getCellData(0, "cntF20")){
            await $c.gus.cfAlertMsg(scwin.MSG_OP_ERR_010);
            return false;
        }

        // if (cntr40Cnt > ds_OnRequest.getCellData(0, "cntF40") ){
        //     await $c.win.alert(ds_OnRequest.getCellData(0, "cntF40"));
        //     await $c.gus.cfAlertMsg(scwin.MSG_OP_ERR_010);
        //     return false;
        // }
    }

    // if (ds_OnRequest.IsUpdated){
    if (ds_OnRequest.getModifiedIndex().length > 0){
        ds_OnRequest.setCellData(0, 'gubun', 'ImportOnRequest');
        if (await $c.gus.cfGetByteLength(txt_errEtcRsn.getValue()) > 100 ){
            await $c.gus.cfAlertMsg(scwin.MSG_OP_ERR_006);
            return;
        }
    }

    // Error Code Check
    // ds_chkErrorCd.DataId = "/cm.zz.RetrieveComboCMD.do?sysCd=OnRequestAdmissionEBC&queryId=retrievechkErrorCd"
    //                       + "&param1=" + ds_ImportOnRequest.getCellData(ds_ImportOnRequest.getRowPosition(),'selfTransClntNo')
    //                       + "&param2=" + ds_ImportOnRequest.getCellData(ds_ImportOnRequest.getRowPosition(), 'onReqNo');
    // ds_chkErrorCd.Reset();
    ds_searchChkErrorCd.set("sysCd", "OnRequestAdmissionEBC");
    ds_searchChkErrorCd.set("queryId", "retrievechkErrorCd");
    ds_searchChkErrorCd.set("param1", ds_ImportOnRequest.getCellData(ds_ImportOnRequest.getRowPosition(), 'selfTransClntNo'));
    ds_searchChkErrorCd.set("param2", ds_ImportOnRequest.getCellData(ds_ImportOnRequest.getRowPosition(), 'onReqNo'));
    var result = await $c.sbm.execute(sbm_chkErrorCd);

    ds_OnRequest.setCellData(0, "selfTransClntNm", ds_OnRequest.getCellData(0, "selfTransClntNm") + " ");

    if (!await $c.win.confirm(MSG_CM_CRM_001)) return;

    //for(i=1;i<=ds_ImportOnRequest.getRowCount();i++){
        //ds_ImportOnRequest.getCellData(i, "chkFlg", "T";
    //}

    if (acb_admitClsCd2.getValue() == "Y"){
        ds_OnRequest.setCellData(0, "prebilgYn", 1);

    }else if (acb_admitClsCd2.getValue() == "N") {
        ds_OnRequest.setCellData(0, "prebilgYn", 0);
    }

    //await $c.win.alert("kkk1::"+acb_admitClsCd2.getValue()+"::2::"+(ds_OnRequest.getCellData(0, "prebilgYn")));
    if (await $c.gus.cfIsNull(ds_OnRequest.getCellData(0, "odrNo"))){
        if (ds_OnRequest.getCellData(0, "lineCd") == "TSL" && await $c.gus.cfIsNull(acb_admitClsCd2.getValue())){
            //await $c.win.alert("kkk2:::"+ds_OnRequest.getCellData(0, "prebilgYn"));
            await $c.win.alert("TSL라인 수입상차요청 승인시에는 반드시 선수납 대상 여부를 기재해야 합니다.");
            return false;
        }
        /*
        if (ds_OnRequest.getCellData(0, "lineCd") == "EAS"
           &&  await $c.gus.cfIsNull(acb_admitClsCd2.getValue())){
            //await $c.win.alert("kkk2:::"+ds_OnRequest.getCellData(0, "prebilgYn"));
            await $c.win.alert("EAS라인 수입상차요청 승인시에는 반드시 선수납 대상 여부를 기재해야 합니다.");
            return false;
        }
        */
        if (ds_OnRequest.getCellData(0, "lineCd") == "SKR" &&  await $c.gus.cfIsNull(acb_admitClsCd2.getValue())){
            //await $c.win.alert("kkk2:::"+ds_OnRequest.getCellData(0, "prebilgYn"));
            await $c.win.alert("SKR라인 수입상차요청 승인시에는 반드시 선수납 대상 여부를 기재해야 합니다.");
            return false;
        }
    }else{
        //await $c.win.alert("기존에 저장된 오더는 그냥 통과");
        //return false;
    }

    //PCY
	if (txt_vsslNm.getValue() != ""){
		txt_vsslNm.setValue(ds_OnRequest.getCellData(0, "vsslCd"));
		ds_OnRequest.setCellData(0, "vsslCd", ds_OnRequest.getCellData(0, "vsslNm"));
	}
    var statusCnt = 0;
    var attachData = udc_attachFile.getData();
    for (var i = 0 ; i < attachData.length ; i++){
        if (attachData[i].rowStatus != "R"){
            statusCnt++;
        }
    }
    if (statusCnt > 0){
        scwin.f_Submit();
    } else {
        $c.sbm.execute(sbm_saveImportOnRequest);
    }
};

