scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch){
    // 선언부
    var param = ",,WDE";
    switch (disGubun) {
        case 1:
            // 자가운송사 Popup   retrieveSelfClnt
            pWhere = ",LOGISCLNT2";
            udc_srchSelfTransCo.setSelectId('retrieveClntList');
            udc_srchSelfTransCo.cfCommonPopUp(scwin.udc_srchSelfTransCo_callBackFunc,pCode,pName,"T",null,null,null,null,pWhere,null,null,pAllSearch,null);
            break;

        case 2:
            var param = "I" + ";" + ed_srchSelfTransCoCd.getValue();
            //상차요청번호 Pop up
            // rtnList = window.showModalDialog('op_301_02_04p2.jsp', param, "dialogWidth:370px; dialogHeight:340px");
            let win_url = "/ui/ds/op/wrkrslts/cywrkrslts/op_301_02_04p2.xml";
            let data = {
                "param"     : param 
            };
            let opts = {
                  id : "searchReqNoPop"
                , popupName : "상차요청번호"
                , modal : true
                , type : "browserPopup"
                , width : 840
                , height : 400
                , title : "상차요청번호"
            };
            var ref = await $c.win.openPopup(win_url, opts, data);
            if (ref != null && ref[0] != 'N/A') {
                ed_srchOnReqNo.setValue(ref[0]);   //상차요청번호
            } else {
                ed_srchOnReqNo.setValue("");   //상차요청번호
            }
            break;

        case 3:
            // 차량번호 Popup
            pCode = ds_ImportOnRequest.getCellData(ds_ImportOnRequest.getRowPosition(), "vehclNo");
            pName = "";
            udc_srchForGrid.setSelectId('retrieveShotVehcl');
            udc_srchForGrid.cfCommonPopUp(scwin.udc_srchForGrid_callBackFunc1,pCode,pName,"T",null,null,null,null,param,null,null,null,null,null,pAllSearch,"차량번호,차랑단축번호,차량번호");
            break;

        case 4:
            // 반납지 Popup
            pWhere = null;
            pName = ds_ImportOnRequest.getCellData(ds_ImportOnRequest.getRowPosition(),  "rtrnWrkPlNm");

            udc_srchForGrid.setSelectId('retrieveReturnWrkPlInfo');
            udc_srchForGrid.cfCommonPopUp(scwin.udc_srchForGrid_callBackFunc2,pCode,pName,"T",null,null,null,null,pWhere,null,null,null,null);
            break;

        default:
            break;
    }
};

