scwin.f_Delete = async function () {
    if (ds_OnRequest.getRowCount() == 0 )  return;
    if (ds_OnRequest.getCellData(0, "odrNo") != "") {
        await $c.gus.cfAlertMsg(scwin.MSG_OP_ERR_007);
        return;
    }
    if (ds_ImportOnRequest.getRowCount() == 0) return;
    var ChkCnt = 0 ;
    var invalidChkCnt = 0;
    for ( var i = 0 ; i < ds_ImportOnRequest.getRowCount(); i++ ) {
        if (ds_ImportOnRequest.getCellData(i, "chkFlg") != "F") {
            ChkCnt++;
        }
        if ((ds_ImportOnRequest.getCellData(i, "selfPrgsStsClsCd") != "W" && ds_ImportOnRequest.getCellData(i, "selfPrgsStsClsCd") != "S")
             && ds_ImportOnRequest.getCellData(i, "chkFlg") != "F" ) {
            invalidChkCnt++;
        }
    }
    if (ChkCnt == 0 ) {
        await $c.gus.cfAlertMsg(scwin.MSG_OP_ERR_008);
        return;
    }
};

