//-------------------------------------------------------------------------
// function name : scwin.uploadComplete
// function desc : Upload File complete
//-------------------------------------------------------------------------
scwin.uploadComplete = function (isSuccess) {
    if (!isSuccess) return;
    var modifyData = udc_attachFile.getModifiedData();
    var attachData = udc_attachFile.getData();
    var attachRowCnt = attachData.length;
    var modifyRowCnt = modifyData.length;

	for ( i = 0 ; i < attachRowCnt; i++) {
        if (attachData[i].status == "Completed"){
            var rowIndex = ds_attach.insertRow();
            if (rowIndex != 0) {
                var fltNxtSeq = parseFloat(ds_attach.getCellData(rowIndex - 1, "attachFileId")) + 1;
                var strNxtSeq = "000" + fltNxtSeq;
                // strNxtSeq = strNxtSeq.substr(strNxtSeq.length - 4, strNxtSeq.length);
                ds_attach.setCellData(rowIndex,"attachFileId", strNxtSeq);
            } else {
                ds_attach.setCellData(rowIndex,"attachFileId", "0001");
            }
            ds_attach.setCellData(rowIndex, "attachFileNm"   , attachData[i].ORIGIN_FILE_NM); //파일명
            ds_attach.setCellData(rowIndex, "attachFileDesc" , attachData[i].FILE_EXPLAIN); //파일설명
            ds_attach.setCellData(rowIndex, "attachFileSiz"  , attachData[i].FILE_SIZE); //파일SIZE
            ds_attach.setCellData(rowIndex, "attachFilePath" , attachData[i].FILE_STORED_PATH + attachData[i].STORED_FILE_NM);	//파일경로
            ds_attach.setCellData(rowIndex, "onReqNo"        , ds_OnRequest.getCellData(0, "onReqNo"));	// 상차요청번호
            ds_attach.setCellData(rowIndex, "selfTransClntNo", ds_OnRequest.getCellData(0, "selfTransClntNo"));	// 자가운송사코드

            ds_attach.modifyRowStatus(i, "C");
        }
	}
    var allJson = ds_attach.getAllJSON();
    for (var i = 0 ; i < ds_attach.getRowCount() ; i++){
        var targetName = allJson[i].attachFilePath.substr(allJson[i].attachFilePath.lastIndexOf('/')+1)
        for (var j = 0 ; j < modifyRowCnt ; j++){
            if (targetName == modifyData[j].STORED_FILE_NM){
                if (modifyData[j].rowStatus == "E"){
                    ds_attach.modifyRowStatus(i, "D");
                    break;
                } else if (modifyData[j].rowStatus == "U"){
                    ds_attach.modifyRowStatus(i, "U");
                    ds_attach.setCellData(i, "attachFileDesc", modifyData[j].FILE_EXPLAIN);
                    break;
                }
            }
        }
    }
    $c.sbm.execute(sbm_saveImportOnRequest);
};

