scwin.f_onoffCntlCheck = function (row) {
	// EVER선사라인, 수입, EMPTY, 의왕CY 반입일 경우 상하차제어
	if (scwin.f_sameYn()
     && ds_OnRequest.getCellData(0, "impExpClsCd") == "I"
     && ds_ImportOnRequest.getCellData(row, "rtrnWrkPlCd") == "4C02"
    ){
        ds_ImportOnRequest.setCellData(row, "onoffCntlYn", 1);
	} else {
		ds_ImportOnRequest.setCellData(row, "onoffCntlYn", 0);
	}
};

scwin.f_sameYn = function () {
	var lineCd = ds_OnRequest.getCellData(0, "lineCd");
