            if (await $c.gus.cfIsNull((ds_OnRequest.getCellData(0, "prebilgYn")))){
                acb_admitClsCd2.setValue("");
            }else if (ds_OnRequest.getCellData(0, "prebilgYn") == 1 ){
                acb_admitClsCd2.setValue("Y");
            }else{
                acb_admitClsCd2.setValue("");
            }
        }
        scwin.bf_admitClsCd = ds_OnRequest.getCellData(0, "admitClsCd");

        // ds_OnRequest event=OnLoadCompleted(rowCnt)
        if (ds_OnRequest.getCellData(0, "admitClsCd") == "A"){
            $c.gus.cfDisableObjects([btn_crtOdr, btn_save]);
        }
        if (ds_OnRequest.getCellData(0, "lineCd") == "OOCL" || ds_OnRequest.getCellData(0, "lineCd") == "WHL" ){
        //$c.gus.cfDisableObjects([btn_save]);
        }else{
        $c.gus.cfDisableObjects([btn_save, btn_cancel]);
        }
        //$c.gus.cfDisableObjects([btn_save, btn_cancel]);

        if (ds_OnRequest.getCellData(0, "odrNo") == "" ){
            if (ds_OnRequest.getCellData(0, "lineCd") == "OOCL" || ds_OnRequest.getCellData(0, "lineCd") == "WHL" ){

            }else{
                $c.gus.cfDisableObjects([btn_save, btn_crtOdr]);
            }

        } else {
            if (ds_OnRequest.getCellData(0, "odrNo") == ""){
                if (ds_OnRequest.getCellData(0, "lineCd") == "OOCL" || ds_OnRequest.getCellData(0, "lineCd") == "WHL" ){
                }else{
                $c.gus.cfDisableObjects([btn_save, btn_cancel]);
                }
            } else {
                $c.gus.cfEnableObjects([btn_save]);
                if (ds_OnRequest.getCellData(0, "admitClsCd") == "O" || ds_OnRequest.getCellData(0, "admitClsCd") == "R"){
                    $c.gus.cfDisableObjects([btn_crtOdr]);
                    $c.gus.cfEnableObjects([btn_cancel]);
                } else if (ds_OnRequest.getCellData(0, "admitClsCd") == "C") {
                    // gr_ImportOnRequest.Editable = "False";
                    gr_ImportOnRequest.setReadOnly("grid", true);

                }
            }
        }

        if ((ds_OnRequest.getCellData(0, "lineCd") == "WHL" || ds_OnRequest.getCellData(0, "lineCd") == "IAL") 
        && ds_OnRequest.getCellData(0, "lane") != "KSI"){
            // gr_ImportOnRequest.Editable = "False";
            gr_ImportOnRequest.setReadOnly("grid", true);
        }

        // ds_ImportOnRequest event=OnLoadCompleted(rowCnt)
        ds_ImportOnRequest.setRowPosition(0);

        var rowCnt = ds_ImportOnRequest.getRowCount();
        txt_totalRows.setValue(rowCnt);
        if (rowCnt == 0 ){
            await $c.gus.cfAlertMsg(MSG_CM_ERR_003 + "\n BL 정보 및 컨테이너 마스터 등록 정보를 확인하십시오.");
        }
        if (acb_admitClsCd.getValue() == "C") {
            gr_ImportOnRequest.setReadOnly("grid", true);
        } else {
            gr_ImportOnRequest.setReadOnly("grid", false);
        }

        var row = ds_ImportOnRequest.getRowPosition();

        if (ds_ImportOnRequest.getCellData(row, 'selfPrgsStsClsCd') == 'W') {
            gr_ImportOnRequest.setReadOnly("grid", false);
            gr_ImportOnRequest.setColumnReadOnly("chkFlg", false);
            gr_ImportOnRequest.setColumnReadOnly("chk", false);
        } else if (ds_ImportOnRequest.getCellData(row, 'selfPrgsStsClsCd') == 'S') {
            gr_ImportOnRequest.setReadOnly("grid", false);
            gr_ImportOnRequest.setColumnReadOnly("chkFlg", false);
            gr_ImportOnRequest.setColumnReadOnly("chk", false);
        } else if (ds_ImportOnRequest.getCellData(row, 'selfPrgsStsClsCd') == 'O') {
            gr_ImportOnRequest.setReadOnly("grid", true);
        } else if (ds_ImportOnRequest.getCellData(row, 'selfPrgsStsClsCd') == 'I') {
            gr_ImportOnRequest.setReadOnly("grid", true);
        }

        //라인코드가 SITC이면 하선지를 반납지로 설정 20200518 최웅식차장
        if (ds_OnRequest.getCellData(0, "lineCd") == "SITC") {
            //승인구분이 승인이 아닌경우에만 기본값변경
            if (ds_OnRequest.getCellData(0, "admitClsCd") != "O") {
                for(var i = 0 ; i < ds_ImportOnRequest.getRowCount();i++){
                    ds_ImportOnRequest.setCellData(i, "rtrnWrkPlNm", ds_ImportOnRequest.getCellData(i, "onWrkPlNm"));
                    ds_ImportOnRequest.setCellData(i, "rtrnWrkPlCd", ds_ImportOnRequest.getCellData(i, "onWrkPlCd"));
                }
            }
        }
        //라인코드가 SITC이고, ODR_CTRL_CLS_CD = 3 인경우에 체선일자 체크
        //await $c.win.alert("lineCd=" + ds_OnRequest.getCellData(0, "lineCd") + ",   odrCtrlClsCd=" + ds_OnRequest.getCellData(0, "odrCtrlClsCd"));
        if (ds_OnRequest.getCellData(0, "lineCd") == "SITC" && ds_OnRequest.getCellData(0, "odrCtrlClsCd") == "3") {
            //승인구분이 승인이 아닌경우에만 기본값변경
            if (ds_OnRequest.getCellData(0, "admitClsCd") != "O") {
                for(var i = 0 ; i < ds_ImportOnRequest.getRowCount(); i++){
                    if (ds_ImportOnRequest.getCellData(i, "rtrnWrkPlCd") != "6T987") {
                        ds_ImportOnRequest.setCellData(i, "rtrnWrkPlNm", "BIT");
                        ds_ImportOnRequest.setCellData(i, "rtrnWrkPlCd", "6P16");
                    }
                }
            }
        }
        //라인코드가 SITC이고, ODR_CTRL_CLS_CD = 5 인경우에 체선일자 체크
        //await $c.win.alert("lineCd=" + ds_OnRequest.getCellData(0, "lineCd") + ",   odrCtrlClsCd=" + ds_OnRequest.getCellData(0, "odrCtrlClsCd"));
        if (ds_OnRequest.getCellData(0, "lineCd") == "SITC" && ds_OnRequest.getCellData(0, "odrCtrlClsCd") == "5") {
            //승인구분이 승인이 아닌경우에만 기본값변경
            if (ds_OnRequest.getCellData(0, "admitClsCd") != "O") {
                for(var i = 0 ; i < ds_ImportOnRequest.getRowCount();i++){
                    if (ds_ImportOnRequest.getCellData(i, "rtrnWrkPlCd") != "6T987") {
                        ds_ImportOnRequest.setCellData(i, "rtrnWrkPlNm", "HBCT");
                        ds_ImportOnRequest.setCellData(i, "rtrnWrkPlCd", "6P12");
                    }
                }
            }
        }
        if (txt_odrNo.getValue() == ""){
            for(var i = 0 ; i < ds_ImportOnRequest.getRowCount();i++ ){
                ds_ImportOnRequest.setCellData(i, "onIntendDt", scwin.nowDt);
                ds_ImportOnRequest.setCellData(i, "rtrnIntendPrdDt", scwin.nextDt);
                ds_ImportOnRequest.setCellData(i, "chk", "T");
            }
        }

        //승인구분이 확인중 상태이고, 부산지역인 경우
        if (   ds_OnRequest.getCellData(0, "admitClsCd") == "S"
            && ds_OnRequest.getCellData(0, "pickuprgnCd") == "PUS") {

            /*
            2016/11/30 박경남과장님 요청 건 , 2017/02/01 박경남과장 추가요청 RCL, EVER
            1. EAS,에버그린 코드4개 (EVER, EMS, HTML, ITS),RCL : ①승인구분(승인), ②자가승인사유(ON-DOCK LINE 미적용), ③체선일자(반출마감일자) -> ①,②,③번 자동세팅
            2. 그 외에 라인들 : ①승인구분(승인) -> ①번만 세팅
            */
            if (ds_OnRequest.getCellData(0, "lineCd") == "EAS"
            || ds_OnRequest.getCellData(0, "lineCd") == "EVER"
            || ds_OnRequest.getCellData(0, "lineCd") == "EMS"
            || ds_OnRequest.getCellData(0, "lineCd") == "HTML"
            || ds_OnRequest.getCellData(0, "lineCd") == "ITS"
            || ds_OnRequest.getCellData(0, "lineCd") == "RCL"
            || ds_OnRequest.getCellData(0, "lineCd") == "COH" 
            || ds_OnRequest.getCellData(0, "lineCd") == "SITC"
            || ds_OnRequest.getCellData(0, "lineCd") == "TCLC"
            || ds_OnRequest.getCellData(0, "lineCd") == "JJS"
            || ds_OnRequest.getCellData(0, "lineCd") == "NOLS"
            || ds_OnRequest.getCellData(0, "lineCd") == "DWH"
            || ds_OnRequest.getCellData(0, "lineCd") == "MAS"
            ) {
                //승인구분을 승인, 자가승인사유를 ON-DOCK LINE 미적용 세팅
                ds_OnRequest.setCellData(0, "admitClsCd", "O");
                acb_jeRmk.setValue("02");
            } else {
                ds_OnRequest.setCellData(0, "admitClsCd", "O");
            }
            $c.gus.cfEnableObjects([btn_crtOdr]);
        }
    }

};

