scwin.sbm_retrieveFile_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        if (ds_attach.getRowCount() > 0){

            // attachFileDesc   : "중기 배정 결과.xlsx"
            // attachFileId     : "0001"
            // attachFileNm     : "중기 배정 결과.xlsx"
            // attachFilePath   : "cm/bc/cstmrcardmgnt/cstmrcardmgnt/중기 배정 결과[1_10101_260211114802680].xlsx"
            // attachFileSiz    : "4113"
            // onReqNo          : "200708210378"
            // regDtm           : "02/11 11:48"
            // rowStatus        : "R"
            // selfTransClntNo  : "100477"
            // seq              : "1"
            var fileJson = [];
            for (var i = 0 ; i < ds_attach.getRowCount() ; i ++){
                var attachFilePath = ds_attach.getCellData(i, "attachFilePath")

                var fileStoredPath = attachFilePath.substr(0, attachFilePath.lastIndexOf('/')+1);
                var storedFileNm = attachFilePath.substr(attachFilePath.lastIndexOf('/')+1);

                var fileInfoData = {
                    FILE_EXPLAIN      : ds_attach.getCellData(i, "attachFileDesc")
                    , FILE_SIZE         : ds_attach.getCellData(i, "attachFileSiz")
                    , FILE_STORED_PATH  : fileStoredPath
                    , ORIGIN_FILE_NM    : ds_attach.getCellData(i, "attachFileNm")
                    , STORED_FILE_NM    : storedFileNm
                    , chk               : "0"
                    , evidClsNm         : ""
                    , hiddenKey         : ""
                    , preView           : ""
                    , receptYn          : ""
                    , rowStatus         : ds_attach.getCellData(i, "rowStatus")
                    , slipKndNm         : ""
                    , slipNo            : ""
                    , status            : ""
                }
                fileJson.push(fileInfoData);
            }
            udc_attachFile.setData(fileJson);
            grp_fileSection.show("");
        }else{
            grp_fileSection.hide("");
        }
    }
};

