scwin.gr_ImportOnRequest_onafteredit = async function (row, columnIndex, value) {
    var colid = gr_ImportOnRequest.getColumnID(columnIndex);
    if (colid == "rtrnWrkPlNm") {
        if (value != ""){
            scwin.f_openCommonPopUp(4, '', '', 'T','T');
        } else {
            value == "";
        }

    } else if (colid == "onIntendDt" || colid == "rtrnIntendPrdDt") {
        await scwin.f_chkDate(row, colid);

        var stDtm   = ds_ImportOnRequest.getCellData(row, "onIntendDt");
        var endDtm  = ds_ImportOnRequest.getCellData(row, "rtrnIntendPrdDt");

        if (stDtm != "" && endDtm != "") {
            if (!await $c.gus.cfIsAfterDate(stDtm, endDtm, false)){
                await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
                return false;
            }
        }
    }
    scwin.f_RowCopy(row, colid)
    scwin.f_onoffCntlCheck(row);
};

