scwin.ds_srchCond_setFunc = function(){
    ds_srchCond.set("onReqNo", ed_srchOnReqNo.getValue());
    ds_srchCond.set("selfTransClntNo", ed_srchSelfTransCoCd.getValue());
    // ds_srchCond.set("impExpClsCd", acb_srchImpExpCls.getValue());
    ds_srchCond.set("impExpClsCd", "");
    ds_srchCond.set("mrn", ed_mrn.getValue());
    ds_srchCond.set("msn", ed_msn.getValue());
    ds_srchCond.set("hsn", ed_hsn.getValue());

};

scwin.ds_srchCond_getFunc = function(){
    ed_srchOnReqNo.setValue(ds_srchCond.get("onReqNo"));
    ed_srchSelfTransCoCd.setValue(ds_srchCond.get("selfTransClntNo"));
    // acb_srchImpExpCls.setValue(ds_srchCond.get("impExpClsCd"));
    ed_mrn.setValue(ds_srchCond.get("mrn"));
    ed_msn.setValue(ds_srchCond.get("msn"));
    ed_hsn.setValue(ds_srchCond.get("hsn"));
};

scwin.crryoutAdmitNo_formatter = function(value, formatValue, rowIdx, colIdx){
    if (value == "0000000000"){
        return "N";
    } else {
        return "Y";
    }
};

scwin.ed_mrn_onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};
